SELECT COALESCE(measurement_type, 'Unknown') AS measurement_type
FROM size_chart_changes
WHERE new_value > old_value;

SELECT count(*) AS number_of_children_clothing_lines
FROM clothing_lines
WHERE target_age_group = 'children';

SELECT COUNT(*) AS total_preferred_mappings
FROM customer_size_mapping
WHERE preferred = 1;

SELECT target_age_group, COUNT(*) AS number_of_lines
FROM clothing_lines
GROUP BY target_age_group;

SELECT COUNT(DISTINCT size_chart_id) AS unique_size_charts
FROM size_charts
WHERE clothing_line_id = 0;
